concept_explanation.custom_spans:
**Creating custom spans:**

```java
import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;

@Service
public class PaymentService {
    private final Tracer tracer;
    private final VisaClient visaClient;

    PaymentService(Tracer tracer, VisaClient c) { this.tracer=tracer; visaClient=c; }

    public PaymentResult process(PaymentRequest req) {
        // Span auto-created for @GetMapping/@PostMapping by Micrometer

        // Custom span for a critical sub-operation:
        Span visaSpan = tracer.nextSpan().name("visa.charge");
        try (Tracer.SpanInScope ws = tracer.withSpan(visaSpan.start())) {
            visaSpan.tag("gateway", "visa");
            visaSpan.tag("amount", String.valueOf(req.amount()));
            VisaResponse resp = visaClient.charge(req);
            visaSpan.tag("responseCode", resp.code());
            return PaymentResult.from(resp);
        } catch (Exception e) {
            visaSpan.error(e);
            throw e;
        } finally {
            visaSpan.end();  // ALWAYS end the span — even on exception
        }
    }
}
```

